"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const levels=[["Low","Review only major changes."],["Standard","Review meaningful changes."],["High","Review every recorded change."]];
export default function SignalThresholdField(){const [active,setActive]=useState(1);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><label className="text-xs font-extrabold uppercase tracking-[.14em] text-[#4a4a4f]">signal threshold</label><div aria-label="Signal threshold" className="mt-4 grid grid-cols-3 gap-2">{levels.map((level,i)=><button key={level[0]} type="button" aria-pressed={active===i} onClick={()=>setActive(i)} className="min-h-11 rounded-xl border border-[#ececee] bg-white text-sm font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{level[0]}</button>)}</div><div aria-hidden className="relative mt-4 h-2 rounded-full bg-[#f4f5f6]"><motion.i className="absolute top-[-4px] h-4 w-4 rounded-full bg-[#ff9950]" animate={{left:`calc(${active*50}% - ${active*8}px)`}} transition={reduced?{duration:0}:{type:"spring",stiffness:320,damping:26}}/></div><p aria-live="polite" className="mt-4 text-sm text-[#4a4a4f]">{levels[active][0]}: {levels[active][1]}</p></section>}
